const items = $input.first().json.items;
if (!items || items.length === 0) return [];
// 只取最新的一篇文章做深度解读
const latestArticle = items[0];
return [{ json: { url: latestArticle.link, title: latestArticle.title } }];

// ============================================
// LLM 配置：根据需求选择模型和供应商
// 修改下面的配置来切换不同的模型
// ============================================

const llmConfig = {
  // 当前支持的模型配置
  kimi: {
    provider: "kimi",
    apiUrl: "https://api.moonshot.cn/v1/chat/completions",
    model: "moonshot-v1-8k",
    // credential 名称（需要在 n8n UI 中创建对应的 credentials）
    credentialName: "llmApiKey"
  },
  deepseek: {
    provider: "deepseek",
    apiUrl: "https://api.deepseek.com/v1/chat/completions",
    model: "deepseek-chat",
    credentialName: "llmApiKey"
  },
  openai: {
    provider: "openai",
    apiUrl: "https://api.openai.com/v1/chat/completions",
    model: "gpt-4o-mini",
    credentialName: "llmApiKey"
  }
};

// 选择当前使用的模型：kimi | deepseek | openai
const currentModel = llmConfig.kimi;

return [{
  json: {
    apiUrl: currentModel.apiUrl,
    model: currentModel.model,
    credentialName: currentModel.credentialName,
    provider: currentModel.provider
  }
}];

