const date = new Date().toISOString().split('T')[0];
// LLM 返回的文章内容
const article = $input.first().json.choices[0].message.content;

// 获取使用的模型名称（用于标注）
const modelName = $('LLM 配置').first().json.model || 'unknown';

return [{
  json: {
    fileName: `/data_output/dailyinfo_ai_${date}.md`,
    model: modelName,
    generatedAt: new Date().toISOString()
  },
  binary: {
    data: {
      data: Buffer.from(article).toString('base64'),
      mimeType: 'text/markdown',
      fileName: `dailyinfo_ai_${date}.md`
    }
  }
}];
